def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def validate_input(nums):
    if not isinstance(nums, list) or not all(isinstance(x, (int, float)) for x in nums):
        raise ValueError("Input must be a list of numbers.")
    if len(nums) < 2:
        raise ValueError("Input list must contain at least two numbers.")

def solve_with_validation(nums, target):
    validate_input(nums)
    return solve(nums, target)
